def divisible_by_digits(start, end):
    result = []
    for num in range(start, end + 1):
        str_num = str(num)
        valid = True
        for digit in str_num:
            if int(digit) == 0 or num % int(digit) != 0:
                valid = False
                break
        if valid:
            result.append(num)
    return result

