def tuple_to_dict(tup):
    if len(tup) % 2 != 0:
        raise ValueError("Tuple must have an even number of elements")

    result = {}
    for i in range(0, len(tup), 2):
        key = tup[i]
        value = tup[i + 1]
        result[key] = value

    return result

