def valid_date(date):
    if not date:
        return False
    parts = date.split('-')
    if len(parts) != 3:
        return False
    month, day, year = parts
    try:
        month = int(month)
        day = int(day)
        year = int(year)
    except ValueError:
        return False
    if not (1 <= month <= 12):
        return False
    if not (1 <= day <= 31):
        return False
    if month in [4, 6, 9, 11] and day == 31:
        return False
    if month == 2 and day > 29:
        return False
    return True

